import java.sql.*;

public class SecureSQLInjection {
    public static void main(String[] args) {
        try {
            String userInput = "admin'; DROP TABLE users; --"; // Malicious input

            // Connect to the database
            Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");

            // Create a prepared statement with parameters
            String query = "SELECT * FROM users WHERE username=?";
            PreparedStatement pstmt = conn.prepareStatement(query);

            // Set the parameter value securely
            pstmt.setString(1, userInput);

            // Execute the query with the securely set parameter
            ResultSet rs = pstmt.executeQuery();

            // Process the result set
            while (rs.next()) {
                System.out.println("Username: " + rs.getString("username"));
                System.out.println("Password: " + rs.getString("password"));
            }

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

